# WebSocket server
def generate_websocket_key(key):
    GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11"
    key = key + GUID
    sha1 = uhashlib.sha1(key.encode())
    return ubinascii.b2a_base64(sha1.digest())[:-1].decode()

def handle_websocket_connection(client_socket):
    try:
        request = client_socket.recv(1024).decode()
        
        if "Upgrade: websocket" in request and "Sec-WebSocket-Key:" in request:
            # Extract WebSocket key
            key_line = [line for line in request.split('\n') if 'Sec-WebSocket-Key:' in line][0]
            key = key_line.split(':')[1].strip()
            
            # Generate WebSocket accept key
            accept_key = generate_websocket_key(key)
            
            # Send WebSocket handshake response
            response = f"HTTP/1.1 101 Switching Protocols\r\n"
            response += f"Upgrade: websocket\r\n"
            response += f"Connection: Upgrade\r\n"
            response += f"Sec-WebSocket-Accept: {accept_key}\r\n\r\n"
            
            client_socket.send(response.encode())
            
            # Handle messages
            while True:
                try:
                    data = client_socket.recv(1024)
                    if not data:
                        break
                    
                    # Parse WebSocket frame
                    if len(data) > 6:
                        # Simple frame parsing (assuming text frame)
                        message = data[6:].decode('utf-8')
                        
                        try:
                            command = json.loads(message)
                            print("Received command:", command)
                            
                            # Handle commands
                            if command.get("action") == "turn_on":
                                print("Turning on device")
                                # Add your device control logic here
                                
                            elif command.get("action") == "turn_off":
                                print("Turning off device")
                                # Add your device control logic here
                                
                        except Exception as e:
                            print("Error parsing JSON:", e)
                            
                except Exception as e:
                    print("Error receiving data:", e)
                    break
                    
    except Exception as e:
        print("WebSocket error:", e)
    finally:
        client_socket.close()

# Start WebSocket server
def start_websocket_server():
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind(('0.0.0.0', 80))
    server_socket.listen(5)
    
    print("WebSocket server listening on port 80")
    
    while True:
        try:
            client_socket, addr = server_socket.accept()
            print("Connection from:", addr)
            handle_websocket_connection(client_socket)
        except Exception as e:
            print("Server error:", e)
            continue

# Start the server
start_websocket_server()